def median(nums):
    if not nums:
        return None

    sorted_nums = sorted(nums)
    n = len(sorted_nums)
    middle_index = (n - 1) // 2

    if n % 2 == 1:
        return sorted_nums[middle_index]
    else:
        return (sorted_nums[middle_index] + sorted_nums[middle_index + 1]) / 2
